    let _toastContainer = null;

    // Creates or returns the persistent toast container div
    function getToastContainer() {
        if (!_toastContainer) {
            _toastContainer = document.createElement('div');
            _toastContainer.id = 'fnp-toast-container';
            document.body.appendChild(_toastContainer);
        }
        return _toastContainer;
    }

    // level: 'info' | 'warning' | 'error'
    // autoDismiss: ms before auto-close (0 = manual only)
    function showToast(message, level = 'info', autoDismiss = 0) {
        const container = getToastContainer();
        const toast     = document.createElement('div');
        toast.className = `fnp-toast fnp-toast-${level}`;

        const icons = { info: '🔵', warning: '⚠️', error: '❌' };
        const defaultDismiss = { info: 3000, warning: 6000, error: 0 };
        const dismissMs = autoDismiss || defaultDismiss[level];

        toast.innerHTML = `
            <span style="flex:1;">${icons[level]} ${message}</span>
            ${level === 'error' || !dismissMs
                ? `<button class="fnp-toast-dismiss" title="Dismiss">✕</button>`
                : ''}
        `;

        const dismiss = () => {
            toast.style.animation = 'fnp-fade-out 0.2s ease forwards';
            setTimeout(() => toast.remove(), 200);
        };

        const btn = toast.querySelector('.fnp-toast-dismiss');
        if (btn) btn.onclick = dismiss;
        if (dismissMs) setTimeout(dismiss, dismissMs);

        container.appendChild(toast);
        return { dismiss };
    }

    // Convenience wrappers
    const toastInfo    = (msg) => showToast(msg, 'info');
    const toastWarning = (msg) => showToast(msg, 'warning');
    const toastError   = (msg) => showToast(msg, 'error');

    // Progress toast — returns object with update() and dismiss()
    function toastProgress(msg) {
        const container = getToastContainer();
        const toast     = document.createElement('div');
        toast.className = 'fnp-toast fnp-toast-info';
        toast.innerHTML = `<span class="fnp-progress-msg" style="flex:1;">🔵 ${msg}</span>`;
        container.appendChild(toast);
        return {
            update: (newMsg) => {
                const el = toast.querySelector('.fnp-progress-msg');
                if (el) el.innerText = `🔵 ${newMsg}`;
            },
            dismiss: () => {
                toast.style.animation = 'fnp-fade-out 0.2s ease forwards';
                setTimeout(() => toast.remove(), 200);
            }
        };
    }

