    // Builds the "Expected values from database" section injected into each OCR prompt.
    // Handles paint spec detection for SP Tag — tells Gemini it won't appear on plate.
// Build expected values context string from DB data
function buildExpected(db, category) {
    if (!db) return '';
    const lines = ['\nExpected values from database (use as reference — read what you actually see):'];
    if (category === 'nameplate') {
        if (db.Model)        lines.push('- Model/Type: ' + db.Model);
        if (db.Style)        lines.push('- Style (SNAP/PCM only): ' + db.Style);
        if (db.Size)         lines.push('- Size: ' + db.Size);
        if (db.Serial)       lines.push('- Serial: ' + db.Serial);
        if (db.Tag)          lines.push('- Tag: ' + db.Tag);
        else                 lines.push('- Tag: none assigned in DB');
        if (db['Set Pressure'])  lines.push('- Set Pressure: ' + db['Set Pressure']);
        if (db['Back Pressure']) lines.push('- Back Pressure: ' + db['Back Pressure']);
        if (db['CDTP'])          lines.push('- CDTP: ' + db['CDTP']);
        if (db['Capacity'])      lines.push('- Capacity: ' + db['Capacity']);
        const spTag = db['SP Tag'] || '';
        if (spTag) {
            if (/paint|ral\s*\d|epoxy|primer|coat|color/i.test(spTag))
                lines.push('- SP Tag: ' + spTag + ' — this is a PAINT SPEC, it will NOT appear on the plate. Read whatever identifier is actually visible instead.');
            else
                lines.push('- SP Tag: ' + spTag);
        }
    } else if (category === 'outlet') {
        if (db.Serial) lines.push('- Serial: ' + db.Serial);
    } else if (category === 'sptag') {
        const spTag = db['SP Tag'] || '';
        if (/paint|ral\s*\d|epoxy|primer|coat|color/i.test(spTag))
            lines.push('- SP Tag in DB: ' + spTag + ' — this is a PAINT SPEC and will NOT appear on this tag. Read whatever identifier is actually on the tag.');
        else if (spTag)
            lines.push('- SP Tag: ' + spTag);
    } else if (category === 'dogtag') {
        if (db.Tag)    lines.push('- Tag: ' + db.Tag);
        if (db.Serial) lines.push('- Serial: ' + db.Serial);
    }
    return lines.join('\n');
}

